I've seen mentions that the object detector isn't completely thread safe, but I can't get it to work at all in a thread pool. Here's a simple test application that first succeeds running detection on the main thread and then the same function crashes when run in a thread pool.
```C++
#include <dlib/image_processing/frontal_face_detector.h>
#include <dlib/threads.h>
#include <iostream>

using namespace dlib;

void detect_task( std::vector<dlib::rectangle>& result)
{
    thread_local dlib::array2d<unsigned char> some_frame(300, 300);
    thread_local dlib::frontal_face_detector detector = get_frontal_face_detector();
    std::vector<dlib::rectangle> dets = detector(some_frame);  //crashes in operator() when run in thread
    result.swap(dets);
}

int main(int argc, const char** argv)
{
    std::cout << "Creating objects" << std::endl;
    thread_pool threads(3);
    future<std::vector<rectangle> > detect_result_future;
    std::vector<rectangle> detect_result;
    std::cout << "Detecting on main thread" << std::endl;
    detect_task(detect_result);
    std::cout << "Detecting threaded" << std::endl;
    uint64 threadid = threads.add_task(&detect_task, detect_result_future);
    std::cout << detect_result_future.get().size();
}
```

This is the stack trace of the crash:
```
#0  0x005f8889 in std::vector<std::vector<dlib::matrix<float, 0l, 1l, dlib::memory_manager_stateless_kernel_1<char>, dlib::row_major_layout>, std::allocator<dlib::matrix<float, 0l, 1l, dlib::memory_manager_stateless_kernel_1<char>, dlib::row_major_layout> > >, std::allocator<std::vector<dlib::matrix<float, 0l, 1l, dlib::memory_manager_stateless_kernel_1<char>, dlib::row_major_layout>, std::allocator<dlib::matrix<float, 0l, 1l, dlib::memory_manager_stateless_kernel_1<char>, dlib::row_major_layout> > > > >::~vector (this=0x1e24, __in_chrg=<optimized out>) at [...snap...]/MinGW/lib/gcc/mingw32/4.9.2/include/c++/bits/stl_vector.h:425
#1  0x004f1e0a in dlib::scan_fhog_pyramid<dlib::pyramid_down<6u>, dlib::default_fhog_feature_extractor>::fhog_filterbank::~fhog_filterbank (this=0x1e0c, __in_chrg=<optimized out>) at [...snip...]/dlib-19.2/dlib/image_processing/../image_processing/scan_fhog_pyramid.h:206
#2  0x00515bae in dlib::processed_weight_vector<dlib::scan_fhog_pyramid<dlib::pyramid_down<6u>, dlib::default_fhog_feature_extractor> >::~processed_weight_vector (this=0x1e00, __in_chrg=<optimized out>) at [...snip...]/dlib-19.2/dlib/image_processing/../image_processing/scan_fhog_pyramid.h:1195
#3  0x0061040e in std::_Destroy<dlib::processed_weight_vector<dlib::scan_fhog_pyramid<dlib::pyramid_down<6u>, dlib::default_fhog_feature_extractor> > > (__pointer=0x1e00) at [...snap...]/MinGW/lib/gcc/mingw32/4.9.2/include/c++/bits/stl_construct.h:93
